UPDATE t_goods
SET stock = stock - #{quantity}, update_time = NOW()
WHERE shop_number = #{shopNumber}
  AND id = #{goodsId}
  AND stock >= #{quantity}
  AND del_flag = 0

UPDATE t_goods
SET stock = stock + #{quantity}, update_time = NOW()
WHERE shop_number = #{shopNumber}
  AND id = #{goodsId}
  AND del_flag = 0

UPDATE t_goods
SET sales = sales + #{quantity}, update_time = NOW()
WHERE shop_number = #{shopNumber}
  AND id = #{goodsId}
  AND del_flag = 0
